parameters.jsCode:
const data = $('Prepare Update Data').first().json;
let upd;
try { upd = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { upd = {}; }
return [{ json: { period: data.period, audience: data.audience, generated_at: new Date().toISOString(), status: 'draft', ...upd } }];
